{
  "family": "Fries-, Photo-Fries, and Anionic Ortho-Fries Rearrangement",
  "candidate": {
    "substrate_smiles": [
      "CC(=O)Oc1ccccc1"
    ],
    "product_smiles": [
      "CC(=O)c1ccccc1O"
    ],
    "optional_reagent_smiles": [
      "Cl[Al](Cl)Cl"
    ],
    "rationale": "This is the classic Fries rearrangement of phenyl acetate to 2-hydroxyacetophenone. It is the simplest and most frequently cited textbook example. The reaction involves the intramolecular rearrangement of an acyl group from a phenolic oxygen to an ortho position on the aromatic ring, catalyzed by a Lewis acid (AlCl3). This example clearly illustrates the core transformation of the Fries rearrangement family.",
    "collision_avoidance_note": "This example uses the simplest possible aromatic system (phenyl) and acyl group (acetyl) to avoid overlap with more complex named reactions involving substituted arenes or specific functional groups. It avoids motifs common in other rearrangements like Claisen (allyl ethers), Beckmann (oximes), or Baeyer-Villiger (ketones/peroxy acids), ensuring it is specific to the Fries rearrangement."
  }
}
